import java.util.*;import java.util.function.*;class A{public static void main(String[]a){var s=new Scanner(System.in);int N=s.nextInt();double[]X=new double[N],T=new double[N];for(int i=0;i<N;i++){X[i]=s.nextInt();T[i]=s.nextInt();}String[]nm={"O(1)","O(log n)","O(n)","O(n log n)","O(n^2)","O(n^2 log n)","O(n^3)","O(2^n)"};DoubleUnaryOperator[]fs={n->1,Math::log,n->n,n->n*Math.log(n),n->n*n,n->n*n*Math.log(n),n->n*n*n,n->Math.pow(2,n)};double be=Double.MAX_VALUE;int bi=0;for(int k=0;k<8;k++){double xy=0,x2=0;boolean ok=true;for(int i=0;i<N;i++){double v=fs[k].applyAsDouble(X[i]);if(!Double.isFinite(v)){ok=false;break;}xy+=T[i]*v;x2+=v*v;}if(!ok||x2==0)continue;double c=xy/x2,e=0;for(int i=0;i<N;i++){double v=fs[k].applyAsDouble(X[i]),d=T[i]-c*v;e+=d*d;}if(e<be){be=e;bi=k;}}System.out.println(nm[bi]);}}